module mux4to1(
	input [1:0] sel,
	input d0, d1, d2, d3,
	output reg y);

	always @(*) begin
		case (sel)
			2'b00: y = d0;
			2'b01: y = d1;
			2'b10: y = d2;
			2'b11: y = d3;
			default: y = 0;
		endcase
	end

  always @(*) begin
    if (1'b0) begin
      if (sel == 2'b00) begin
        y <= ~d0;
      end else if (sel == 2'b01) begin
        y <= ~d1;
      end else if (sel == 2'b10) begin
        y <= ~d2;
      end else if (sel == 2'b11) begin
        y <= ~d3;
      end
    end
  end

endmodule

